import { describe, it, expect } from "vitest";
import { createRoomSchema, joinRoomSchema } from "./rooms.js";

describe("createRoomSchema", () => {
  const validPayload = {
    name: "IPL 2026 Auction",
    defaultPurse: 10000, // 100 Crore = 10000 Lakhs
    squadSizeCap: 18,
    timerSeconds: 15,
    incrementRule: [{ threshold: 0, increment: 5 }],
    teams: [
      { name: "Mumbai Indians" },
      { name: "Chennai Super Kings" }
    ],
    players: [
      { name: "Jasprit Bumrah", category: "Bowler", basePrice: 200 },
      { name: "MS Dhoni", category: "Wicketkeeper", basePrice: 200 }
    ]
  };

  it("should accept a valid payload", () => {
    const res = createRoomSchema.safeParse(validPayload);
    expect(res.success).toBe(true);
  });

  it("should reject duplicate team names", () => {
    const payload = {
      ...validPayload,
      teams: [
        { name: "Mumbai Indians" },
        { name: "mumbai indians" }
      ]
    };
    const res = createRoomSchema.safeParse(payload);
    expect(res.success).toBe(false);
  });

  it("should reject empty teams array", () => {
    const payload = {
      ...validPayload,
      teams: []
    };
    const res = createRoomSchema.safeParse(payload);
    expect(res.success).toBe(false);
  });

  it("should reject empty players array", () => {
    const payload = {
      ...validPayload,
      players: []
    };
    const res = createRoomSchema.safeParse(payload);
    expect(res.success).toBe(false);
  });

  it("should reject non-positive base price", () => {
    const payload = {
      ...validPayload,
      players: [
        { name: "A", category: "Bowler", basePrice: 0 }
      ]
    };
    const res = createRoomSchema.safeParse(payload);
    expect(res.success).toBe(false);
  });
});

describe("joinRoomSchema", () => {
  it("should accept spectator without teamId", () => {
    const res = joinRoomSchema.safeParse({
      displayName: "John Spectator",
      role: "SPECTATOR",
      teamId: null,
      anonId: "anon-123"
    });
    expect(res.success).toBe(true);
  });

  it("should accept team owner with teamId", () => {
    const res = joinRoomSchema.safeParse({
      displayName: "Jane Owner",
      role: "TEAM_OWNER",
      teamId: "team-id-1",
      anonId: "anon-456"
    });
    expect(res.success).toBe(true);
  });

  it("should reject spectator with teamId", () => {
    const res = joinRoomSchema.safeParse({
      displayName: "Bad Spectator",
      role: "SPECTATOR",
      teamId: "team-id-1",
      anonId: "anon-789"
    });
    expect(res.success).toBe(false);
  });

  it("should reject team owner without teamId", () => {
    const res = joinRoomSchema.safeParse({
      displayName: "Bad Owner",
      role: "TEAM_OWNER",
      teamId: null,
      anonId: "anon-789"
    });
    expect(res.success).toBe(false);
  });
});

import * as jose from "jose";

const JWT_SECRET = new TextEncoder().encode(
  process.env.ROOM_JWT_SECRET || "fallback-secret-for-development-only-replace-in-env"
);

export interface CommissionerPayload {
  userId: string;
  email: string;
  name: string;
  role: "COMMISSIONER";
}

export interface ParticipantPayload {
  roomId: string;
  participantId: string;
  role: "TEAM_OWNER" | "SPECTATOR";
  teamId?: string | null;
}

export async function signCommissionerToken(payload: CommissionerPayload): Promise<string> {
  return new jose.SignJWT({ ...payload })
    .setProtectedHeader({ alg: "HS256" })
    .setIssuedAt()
    .setExpirationTime("24h")
    .sign(JWT_SECRET);
}

export async function verifyCommissionerToken(token: string): Promise<CommissionerPayload | null> {
  try {
    const { payload } = await jose.jwtVerify(token, JWT_SECRET);
    return payload as unknown as CommissionerPayload;
  } catch (err) {
    return null;
  }
}

export async function signParticipantToken(payload: ParticipantPayload): Promise<string> {
  return new jose.SignJWT({ ...payload })
    .setProtectedHeader({ alg: "HS256" })
    .setIssuedAt()
    .setExpirationTime("24h")
    .sign(JWT_SECRET);
}

export async function verifyParticipantToken(token: string): Promise<ParticipantPayload | null> {
  try {
    const { payload } = await jose.jwtVerify(token, JWT_SECRET);
    return payload as unknown as ParticipantPayload;
  } catch (err) {
    return null;
  }
}

import { NextRequest, NextResponse } from "next/server";
import { signupSchema } from "@bidstand/shared";
import { prisma } from "@bidstand/db";
import bcryptjs from "bcryptjs";

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const parsed = signupSchema.safeParse(body);

    if (!parsed.success) {
      return NextResponse.json(
        { ok: false, code: "INVALID_INPUT", message: parsed.error.issues[0].message },
        { status: 400 }
      );
    }

    const { email, password, name } = parsed.data;

    // Check if user already exists
    const existing = await prisma.user.findUnique({ where: { email } });
    if (existing) {
      return NextResponse.json(
        { ok: false, code: "USER_EXISTS", message: "A user with this email already exists" },
        { status: 409 }
      );
    }

    // Hash password
    const salt = await bcryptjs.genSalt(10);
    const passwordHash = await bcryptjs.hash(password, salt);

    // Create user
    const user = await prisma.user.create({
      data: {
        email,
        passwordHash,
        name,
      },
    });

    return NextResponse.json({
      ok: true,
      user: {
        id: user.id,
        email: user.email,
        name: user.name,
      },
    });
  } catch (error: any) {
    console.error("Signup error:", error);
    return NextResponse.json(
      { ok: false, code: "SERVER_ERROR", message: "An unexpected error occurred" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { loginSchema } from "@bidstand/shared";
import { prisma } from "@bidstand/db";
import bcryptjs from "bcryptjs";
import { signCommissionerToken } from "@/lib/auth";

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const parsed = loginSchema.safeParse(body);

    if (!parsed.success) {
      return NextResponse.json(
        { ok: false, code: "INVALID_INPUT", message: parsed.error.issues[0].message },
        { status: 400 }
      );
    }

    const { email, password } = parsed.data;

    // Find user
    const user = await prisma.user.findUnique({ where: { email } });
    if (!user) {
      return NextResponse.json(
        { ok: false, code: "INVALID_CREDENTIALS", message: "Invalid email or password" },
        { status: 401 }
      );
    }

    // Compare passwords
    const match = await bcryptjs.compare(password, user.passwordHash);
    if (!match) {
      return NextResponse.json(
        { ok: false, code: "INVALID_CREDENTIALS", message: "Invalid email or password" },
        { status: 401 }
      );
    }

    // Sign Commissioner JWT
    const token = await signCommissionerToken({
      userId: user.id,
      email: user.email,
      name: user.name,
      role: "COMMISSIONER",
    });

    const response = NextResponse.json({
      ok: true,
      user: {
        id: user.id,
        email: user.email,
        name: user.name,
      },
    });

    // Set HTTP-only cookie
    response.cookies.set("commissioner_token", token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === "production",
      path: "/",
      maxAge: 60 * 60 * 24, // 24 hours
    });

    return response;
  } catch (error: any) {
    console.error("Login error:", error);
    return NextResponse.json(
      { ok: false, code: "SERVER_ERROR", message: "An unexpected error occurred" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { createRoomSchema } from "@bidstand/shared";
import { prisma } from "@bidstand/db";
import { verifyCommissionerToken } from "@/lib/auth";

// Helper to generate 6-character room code
function generateCode(): string {
  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
  let code = "";
  for (let i = 0; i < 6; i++) {
    code += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return code;
}

export async function POST(req: NextRequest) {
  try {
    // 1. Authenticate commissioner
    const cookie = req.cookies.get("commissioner_token");
    if (!cookie) {
      return NextResponse.json(
        { ok: false, code: "UNAUTHORIZED", message: "You must be logged in as a Commissioner" },
        { status: 401 }
      );
    }

    const commissioner = await verifyCommissionerToken(cookie.value);
    if (!commissioner) {
      return NextResponse.json(
        { ok: false, code: "UNAUTHORIZED", message: "Session invalid or expired" },
        { status: 401 }
      );
    }

    // 2. Parse and validate body
    const body = await req.json();
    const parsed = createRoomSchema.safeParse(body);
    if (!parsed.success) {
      return NextResponse.json(
        { ok: false, code: "INVALID_INPUT", message: parsed.error.issues[0].message },
        { status: 400 }
      );
    }

    const { name, defaultPurse, squadSizeCap, roleCaps, timerSeconds, incrementRule, teams, players } = parsed.data;

    // 3. Generate unique room code (collision retry up to 5 times)
    let code = "";
    let roomWithCode = null;
    let retries = 0;
    do {
      code = generateCode();
      roomWithCode = await prisma.room.findUnique({ where: { code } });
      retries++;
    } while (roomWithCode && retries < 5);

    if (roomWithCode) {
      return NextResponse.json(
        { ok: false, code: "CODE_COLLISION", message: "Unable to generate unique room code. Please try again." },
        { status: 500 }
      );
    }

    // 4. Create Room, Teams, and Players in a single transaction
    const room = await prisma.$transaction(async (tx) => {
      const createdRoom = await tx.room.create({
        data: {
          code,
          name,
          commissionerId: commissioner.userId,
          defaultPurse,
          squadSizeCap,
          roleCaps: roleCaps as any,
          timerSeconds,
          incrementRule: incrementRule as any,
          status: "LOBBY",
        },
      });

      // Create all Teams
      await Promise.all(
        teams.map((t) =>
          tx.team.create({
            data: {
              roomId: createdRoom.id,
              name: t.name,
              purseTotal: defaultPurse,
              purseRemaining: defaultPurse,
            },
          })
        )
      );

      // Create all Items (Players)
      await Promise.all(
        players.map((p, index) =>
          tx.item.create({
            data: {
              roomId: createdRoom.id,
              name: p.name,
              category: p.category,
              basePrice: p.basePrice,
              imageUrl: p.imageUrl || null,
              auctionOrder: index + 1,
              status: "PENDING",
            },
          })
        )
      );

      return createdRoom;
    });

    const teamCount = teams.length;
    const playerCount = players.length;

    return NextResponse.json({
      ok: true,
      room: {
        id: room.id,
        code: room.code,
        name: room.name,
        status: room.status,
        teamCount,
        playerCount,
      },
    });
  } catch (error: any) {
    console.error("Room creation error:", error);
    return NextResponse.json(
      { ok: false, code: "SERVER_ERROR", message: "An unexpected error occurred" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { joinRoomSchema, roomCodeSchema } from "@bidstand/shared";
import { prisma } from "@bidstand/db";
import { signParticipantToken } from "@/lib/auth";

export async function POST(
  req: NextRequest,
  { params }: { params: { code: string } }
) {
  try {
    // 1. Validate room code parameter
    const codeParsed = roomCodeSchema.safeParse({ code: params.code.toUpperCase() });
    if (!codeParsed.success) {
      return NextResponse.json(
        { ok: false, code: "INVALID_ROOM_CODE", message: "Room code must be 6 alphanumeric characters" },
        { status: 400 }
      );
    }

    const { code } = codeParsed.data;

    // Lookup room
    const room = await prisma.room.findUnique({
      where: { code },
      include: { teams: true },
    });

    if (!room) {
      return NextResponse.json(
        { ok: false, code: "ROOM_NOT_FOUND", message: "The requested auction room does not exist" },
        { status: 404 }
      );
    }

    // 2. Validate request body
    const body = await req.json();
    const parsed = joinRoomSchema.safeParse(body);
    if (!parsed.success) {
      return NextResponse.json(
        { ok: false, code: "INVALID_INPUT", message: parsed.error.issues[0].message },
        { status: 400 }
      );
    }

    const { displayName, role, teamId, anonId } = parsed.data;

    // 3. Rejoin logic: check if participant already exists by roomId + anonId
    const existingParticipant = await prisma.participant.findUnique({
      where: { roomId_anonId: { roomId: room.id, anonId } },
      include: { team: true },
    });

    if (existingParticipant) {
      // Re-sign token and return success
      const token = await signParticipantToken({
        roomId: room.id,
        participantId: existingParticipant.id,
        role: existingParticipant.role,
        teamId: existingParticipant.team?.id || null,
      });

      const response = NextResponse.json({
        ok: true,
        participant: {
          id: existingParticipant.id,
          displayName: existingParticipant.displayName,
          role: existingParticipant.role,
          teamId: existingParticipant.team?.id || null,
        },
      });

      response.cookies.set("room_token", token, {
        httpOnly: true,
        secure: process.env.NODE_ENV === "production",
        path: "/",
        maxAge: 60 * 60 * 24, // 24 hours
      });

      return response;
    }

    // 4. Create new participant
    let participantId = "";
    let finalTeamId: string | null = null;

    if (role === "TEAM_OWNER") {
      if (!teamId) {
        return NextResponse.json(
          { ok: false, code: "TEAM_REQUIRED", message: "Team Owner role requires selecting a team" },
          { status: 400 }
        );
      }

      // Verify team is in this room
      const targetTeam = room.teams.find((t) => t.id === teamId);
      if (!targetTeam) {
        return NextResponse.json(
          { ok: false, code: "TEAM_NOT_FOUND", message: "Selected team is not part of this room" },
          { status: 404 }
        );
      }

      // Verify team is unclaimed
      if (targetTeam.ownerParticipantId) {
        return NextResponse.json(
          { ok: false, code: "TEAM_ALREADY_CLAIMED", message: "This team has already been claimed by another owner" },
          { status: 409 }
        );
      }

      // Claim team in transaction
      const result = await prisma.$transaction(async (tx) => {
        const participant = await tx.participant.create({
          data: {
            roomId: room.id,
            displayName,
            role,
            anonId,
            connected: true,
          },
        });

        await tx.team.update({
          where: { id: teamId },
          data: { ownerParticipantId: participant.id },
        });

        return participant;
      });

      participantId = result.id;
      finalTeamId = teamId;
    } else {
      // Spectator
      const participant = await prisma.participant.create({
        data: {
          roomId: room.id,
          displayName,
          role,
          anonId,
          connected: true,
        },
      });

      participantId = participant.id;
    }

    // 5. Sign token and set cookie
    const token = await signParticipantToken({
      roomId: room.id,
      participantId,
      role,
      teamId: finalTeamId,
    });

    const response = NextResponse.json({
      ok: true,
      participant: {
        id: participantId,
        displayName,
        role,
        teamId: finalTeamId,
      },
    });

    response.cookies.set("room_token", token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === "production",
      path: "/",
      maxAge: 60 * 60 * 24, // 24 hours
    });

    return response;
  } catch (error: any) {
    console.error("Join room error:", error);
    return NextResponse.json(
      { ok: false, code: "SERVER_ERROR", message: "An unexpected error occurred" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { roomCodeSchema } from "@bidstand/shared";
import { prisma } from "@bidstand/db";

export async function GET(
  req: NextRequest,
  { params }: { params: { code: string } }
) {
  try {
    const codeParsed = roomCodeSchema.safeParse({ code: params.code.toUpperCase() });
    if (!codeParsed.success) {
      return NextResponse.json(
        { ok: false, code: "INVALID_ROOM_CODE", message: "Room code must be 6 alphanumeric characters" },
        { status: 400 }
      );
    }

    const { code } = codeParsed.data;

    const room = await prisma.room.findUnique({
      where: { code },
      include: {
        teams: {
          include: {
            ownerParticipant: true
          }
        },
        participants: true
      }
    });

    if (!room) {
      return NextResponse.json(
        { ok: false, code: "ROOM_NOT_FOUND", message: "Room not found" },
        { status: 404 }
      );
    }

    return NextResponse.json({
      ok: true,
      room: {
        id: room.id,
        code: room.code,
        name: room.name,
        status: room.status,
        defaultPurse: room.defaultPurse,
        squadSizeCap: room.squadSizeCap,
        roleCaps: room.roleCaps,
        timerSeconds: room.timerSeconds,
        incrementRule: room.incrementRule,
      },
      teams: room.teams.map(t => ({
        id: t.id,
        name: t.name,
        purseTotal: t.purseTotal,
        purseRemaining: t.purseRemaining,
        ownerParticipantId: t.ownerParticipantId,
        ownerParticipantName: t.ownerParticipant?.displayName || null
      })),
      participants: room.participants.map(p => ({
        id: p.id,
        displayName: p.displayName,
        role: p.role,
        connected: p.connected,
        lastSeenAt: p.lastSeenAt
      }))
    });
  } catch (error: any) {
    console.error("Fetch room error:", error);
    return NextResponse.json(
      { ok: false, code: "SERVER_ERROR", message: "An unexpected error occurred" },
      { status: 500 }
    );
  }
}

export async function apiRequest(url: string, method: string, body?: any) {
  const res = await fetch(url, {
    method,
    headers: {
      "Content-Type": "application/json",
    },
    body: body ? JSON.stringify(body) : undefined,
  });

  const data = await res.json();
  if (!res.ok) {
    throw new Error(data.message || "An error occurred");
  }
  return data;
}

