}

"use client";

import React, { useState } from "react";
import { useRouter } from "next/navigation";
import { apiRequest } from "@/lib/api";

const DEFAULT_TEAMS = "Mumbai Indians, Chennai Super Kings, Royal Challengers Bengaluru, Kolkata Knight Riders";

const DEFAULT_PLAYERS = `Virat Kohli, Batsman, 200
Jasprit Bumrah, Bowler, 200
MS Dhoni, Wicketkeeper, 200
Ravindra Jadeja, All-rounder, 150
Suryakumar Yadav, Batsman, 150
Hardik Pandya, All-rounder, 150
Rashid Khan, Bowler, 150
Heinrich Klaasen, Wicketkeeper, 150`;

export default function CreateRoomPage() {
  const router = useRouter();
  const [name, setName] = useState("");
  const [defaultPurse, setDefaultPurse] = useState(10000); // 100 Crore in Lakhs
  const [squadSizeCap, setSquadSizeCap] = useState(18);
  const [timerSeconds, setTimerSeconds] = useState(15);

  // Teams inputs
  const [teamsText, setTeamsText] = useState(DEFAULT_TEAMS);
  // Players inputs
  const [playersText, setPlayersText] = useState(DEFAULT_PLAYERS);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      // Parse teams
      const teamList = teamsText
        .split(",")
        .map((t) => t.trim())
        .filter((t) => t.length > 0)
        .map((name) => ({ name }));

      if (teamList.length === 0) {
        throw new Error("At least one team is required");
      }

      // Parse players (CSV format: Name, Category, Base Price)
      const playerList = playersText
        .split("\n")
        .map((line) => line.trim())
        .filter((line) => line.length > 0)
        .map((line) => {
          const parts = line.split(",");
          if (parts.length < 3) {
            throw new Error(`Invalid player format on line: "${line}". Format: Name, Category, BasePrice`);
          }
          const basePrice = parseInt(parts[2].trim(), 10);
          if (isNaN(basePrice) || basePrice <= 0) {
            throw new Error(`Invalid base price on line: "${line}"`);
          }
          return {
            name: parts[0].trim(),
            category: parts[1].trim(),
            basePrice,
          };
        });

      if (playerList.length === 0) {
        throw new Error("At least one player is required in the pool");
      }

      const body = {
        name,
        defaultPurse,
        squadSizeCap,
        timerSeconds,
        incrementRule: [
          { threshold: 0, increment: 5 },     // +5 lakhs below 100 lakhs
          { threshold: 100, increment: 10 },  // +10 lakhs above 100 lakhs
          { threshold: 500, increment: 20 },  // +20 lakhs above 500 lakhs
        ],
        teams: teamList,
        players: playerList,
      };

      const data = await apiRequest("/api/rooms", "POST", body);
      if (data.ok) {
        router.push(`/room/${data.room.code}/lobby`);
      }
    } catch (err: any) {
      setError(err.message || "Failed to create room");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto px-6 py-10 w-full flex-1">
      <h1 className="text-3xl font-bold text-slate-100 mb-2">Create Auction Room</h1>
      <p className="text-slate-400 mb-8">Configure your room settings, teams, and player draft pool.</p>

      {error && <p className="text-red-400 bg-red-950/40 border border-red-900 px-4 py-3 rounded-lg mb-6">{error}</p>}

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 space-y-4">
          <h2 className="text-xl font-semibold text-slate-200 border-b border-slate-800 pb-2">Room Basics</h2>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Room Name</label>
            <input
              type="text"
              placeholder="e.g. IPL 2026 Mega Auction"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-slate-100 focus:outline-none focus:border-blue-500"
              required
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-300 mb-1">Default Purse (Lakhs)</label>
              <input
                type="number"
                value={defaultPurse}
                onChange={(e) => setDefaultPurse(parseInt(e.target.value, 10))}
                className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-slate-100 focus:outline-none focus:border-blue-500"
                required
              />
              <span className="text-xs text-slate-500">e.g. 10000 = ₹100 Crore</span>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-300 mb-1">Squad Size Cap</label>
              <input
                type="number"
                value={squadSizeCap}
                onChange={(e) => setSquadSizeCap(parseInt(e.target.value, 10))}
                className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-slate-100 focus:outline-none focus:border-blue-500"
                required
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-300 mb-1">Bid Timer (seconds)</label>
              <input
                type="number"
                value={timerSeconds}
                onChange={(e) => setTimerSeconds(parseInt(e.target.value, 10))}
                className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-slate-100 focus:outline-none focus:border-blue-500"
                required
              />
            </div>
          </div>
        </div>

        <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 space-y-4">
          <h2 className="text-xl font-semibold text-slate-200 border-b border-slate-800 pb-2">Teams List</h2>
          <p className="text-xs text-slate-400">Comma-separated list of team names.</p>
          <textarea
            rows={2}
            value={teamsText}
            onChange={(e) => setTeamsText(e.target.value)}
            className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-slate-100 focus:outline-none focus:border-blue-500 font-mono text-sm"
            required
          />
        </div>

        <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 space-y-4">
          <h2 className="text-xl font-semibold text-slate-200 border-b border-slate-800 pb-2">Players Draft Pool</h2>
          <p className="text-xs text-slate-400">One player per line. Format: Name, Category, Base Price (in Lakhs)</p>
          <textarea
            rows={8}
            value={playersText}
            onChange={(e) => setPlayersText(e.target.value)}
            className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-slate-100 focus:outline-none focus:border-blue-500 font-mono text-sm"
            required
          />
        </div>

        <div className="flex gap-4">
          <button
            type="button"
            onClick={() => router.back()}
            className="flex-1 bg-slate-800 hover:bg-slate-700 text-slate-300 font-semibold py-3 rounded-lg transition"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-semibold py-3 rounded-lg transition disabled:opacity-50"
          >
            {loading ? "Creating Room..." : "Create Room"}
          </button>
        </div>
      </form>
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { apiRequest } from "@/lib/api";

function getOrCreateAnonId(): string {
  if (typeof window === "undefined") return "";
  let id = localStorage.getItem("bidstand_anon_id");
  if (!id) {
    id = "anon_" + Math.random().toString(36).substring(2, 15);
    localStorage.setItem("bidstand_anon_id", id);
  }
  return id;
}

export default function JoinRoomPage({ params }: { params: { code: string } }) {
  const router = useRouter();
  const code = params.code.toUpperCase();

  const [room, setRoom] = useState<any>(null);
  const [teams, setTeams] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitLoading, setSubmitLoading] = useState(false);
  const [error, setError] = useState("");

  // Form states
  const [displayName, setDisplayName] = useState("");
  const [role, setRole] = useState<"TEAM_OWNER" | "SPECTATOR">("TEAM_OWNER");
  const [selectedTeamId, setSelectedTeamId] = useState("");

  useEffect(() => {
    async function loadRoomDetails() {
      try {
        const data = await apiRequest(`/api/rooms/${code}`, "GET");
        if (data.ok) {
          setRoom(data.room);
          setTeams(data.teams);
          // Set default team selection if any unclaimed teams exist
          const unclaimed = data.teams.filter((t: any) => !t.ownerParticipantId);
          if (unclaimed.length > 0) {
            setSelectedTeamId(unclaimed[0].id);
          }
        }
      } catch (err: any) {
        setError(err.message || "Failed to load room details");
      } finally {
        setLoading(false);
      }
    }
    loadRoomDetails();
  }, [code]);

  const handleJoin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSubmitLoading(true);

    try {
      const anonId = getOrCreateAnonId();
      const body = {
        displayName,
        role,
        teamId: role === "TEAM_OWNER" ? selectedTeamId : null,
        anonId,
      };

      const data = await apiRequest(`/api/rooms/${code}/join`, "POST", body);
      if (data.ok) {
        router.push(`/room/${code}/lobby`);
      }
    } catch (err: any) {
      setError(err.message || "Failed to join room");
    } finally {
      setSubmitLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="max-w-md mx-auto px-4 py-20 text-center text-slate-400">
        Loading room details...
      </div>
    );
  }

  if (error && !room) {
    return (
      <div className="max-w-md mx-auto px-4 py-20 text-center">
        <h2 className="text-2xl font-bold text-red-400 mb-4">Error</h2>
        <p className="text-slate-400 mb-6">{error}</p>
        <button
          onClick={() => router.push("/")}
          className="bg-slate-800 hover:bg-slate-700 text-slate-100 px-6 py-2.5 rounded-lg transition"
        >
          Back to Home
        </button>
      </div>
    );
  }

  const unclaimedTeams = teams.filter((t) => !t.ownerParticipantId);

  return (
    <div className="max-w-md mx-auto px-4 py-12 w-full flex-1 flex flex-col justify-center">
      <div className="bg-slate-900 border border-slate-800 rounded-xl p-8 shadow-xl">
        <div className="text-center mb-8">
          <span className="text-xs font-semibold text-blue-400 uppercase tracking-widest bg-blue-500/10 border border-blue-500/20 px-3 py-1 rounded-full mb-3 inline-block">
            Joining Room
          </span>
          <h1 className="text-2xl font-bold text-slate-100">{room?.name}</h1>
          <p className="text-slate-400 font-mono mt-1 text-lg">Code: {code}</p>
        </div>

        {error && <p className="text-red-400 text-sm bg-red-950/40 border border-red-900 px-4 py-3 rounded-lg mb-6">{error}</p>}

        <form onSubmit={handleJoin} className="space-y-6">
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Display Name</label>
            <input
              type="text"
              placeholder="Enter your name"
              value={displayName}
              onChange={(e) => setDisplayName(e.target.value)}
              className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2.5 text-slate-100 focus:outline-none focus:border-blue-500"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-2">Select Role</label>
            <div className="grid grid-cols-2 gap-4">
              <button
                type="button"
                onClick={() => setRole("TEAM_OWNER")}
                className={`py-3 px-4 rounded-lg font-semibold border transition text-center flex flex-col items-center justify-center ${
                  role === "TEAM_OWNER"
                    ? "bg-blue-600/10 border-blue-500 text-blue-400"
                    : "bg-slate-950 border-slate-800 text-slate-400 hover:border-slate-700"
                }`}
              >
                <span className="text-lg">🏏</span>
                <span className="text-sm mt-1">Team Owner</span>
              </button>
              <button
                type="button"
                onClick={() => setRole("SPECTATOR")}
                className={`py-3 px-4 rounded-lg font-semibold border transition text-center flex flex-col items-center justify-center ${
                  role === "SPECTATOR"
                    ? "bg-blue-600/10 border-blue-500 text-blue-400"
                    : "bg-slate-950 border-slate-800 text-slate-400 hover:border-slate-700"
                }`}
              >
                <span className="text-lg">👀</span>
                <span className="text-sm mt-1">Spectator</span>
              </button>
            </div>
          </div>

          {role === "TEAM_OWNER" && (
            <div>
              <label className="block text-sm font-medium text-slate-300 mb-2">Claim Franchise / Team</label>
              {unclaimedTeams.length === 0 ? (
                <p className="text-yellow-500 text-sm bg-yellow-950/40 border border-yellow-900 px-4 py-3 rounded-lg">
                  All teams are already claimed. You can only join as a Spectator.
                </p>
              ) : (
                <select
                  value={selectedTeamId}
                  onChange={(e) => setSelectedTeamId(e.target.value)}
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2.5 text-slate-100 focus:outline-none focus:border-blue-500"
                  required
                >
                  {unclaimedTeams.map((team) => (
                    <option key={team.id} value={team.id}>
                      {team.name}
                    </option>
                  ))}
                </select>
              )}
            </div>
          )}

          <button
            type="submit"
            disabled={submitLoading || (role === "TEAM_OWNER" && unclaimedTeams.length === 0)}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-semibold py-3 rounded-lg transition disabled:opacity-50"
          >
            {submitLoading ? "Joining..." : "Enter Lobby"}
          </button>
        </form>
      </div>
    </div>
  );
}

