import { io, Socket } from "socket.io-client";

let socket: Socket | null = null;

export function connectSocket(token: string): Socket {
  if (socket) {
    socket.disconnect();
  }

  const url = process.env.NEXT_PUBLIC_REALTIME_URL || "http://localhost:4000";

  socket = io(url, {
    auth: {
      token,
    },
    transports: ["websocket"],
  });

  return socket;
}

export function getSocket(): Socket | null {
  return socket;
}

export function disconnectSocket() {
  if (socket) {
    socket.disconnect();
    socket = null;
  }
}

import { Socket } from "socket.io";
import { prisma } from "@bidstand/db";

export interface SocketUserPayload {
  roomId: string;
  participantId: string;
  role: "COMMISSIONER" | "TEAM_OWNER" | "SPECTATOR";
  teamId?: string | null;
}

export async function handleLobbyConnection(socket: Socket, payload: SocketUserPayload) {
  const { roomId, participantId } = payload;

  try {
    // 1. Join Socket.io room
    socket.join(roomId);

    // 2. Update participant state to connected
    await prisma.participant.update({
      where: { id: participantId },
      data: {
        connected: true,
        lastSeenAt: new Date(),
      },
    });

    // 3. Broadcast the updated lobby snapshot
    await broadcastLobbyState(socket.server, roomId);

    // 4. Handle disconnect
    socket.on("disconnect", async () => {
      try {
        await prisma.participant.update({
          where: { id: participantId },
          data: {
            connected: false,
            lastSeenAt: new Date(),
          },
        });
        await broadcastLobbyState(socket.server, roomId);
      } catch (err) {
        console.error("Error updating connection status on disconnect:", err);
      }
    });
  } catch (error) {
    console.error("Error in handleLobbyConnection:", error);
    socket.emit("error", { message: "Failed to initialize lobby session" });
  }
}

export async function broadcastLobbyState(io: any, roomId: string) {
  try {
    const room = await prisma.room.findUnique({
      where: { id: roomId },
      include: {
        teams: {
          include: {
            ownerParticipant: true,
          },
        },
        participants: true,
      },
    });

    if (!room) return;

    const payload = {
      ok: true,
      room: {
        id: room.id,
        code: room.code,
        name: room.name,
        status: room.status,
        defaultPurse: room.defaultPurse,
        squadSizeCap: room.squadSizeCap,
        roleCaps: room.roleCaps,
        timerSeconds: room.timerSeconds,
        incrementRule: room.incrementRule,
      },
      teams: room.teams.map((t) => ({
        id: t.id,
        name: t.name,
        purseTotal: t.purseTotal,
        purseRemaining: t.purseRemaining,
        ownerParticipantId: t.ownerParticipantId,
        ownerParticipantName: t.ownerParticipant?.displayName || null,
      })),
      participants: room.participants.map((p) => ({
        id: p.id,
        displayName: p.displayName,
        role: p.role,
        connected: p.connected,
        lastSeenAt: p.lastSeenAt,
      })),
    };

    io.to(roomId).emit("room:state", payload);
  } catch (error) {
    console.error("Error broadcasting lobby state:", error);
  }
}

import express from "express";
import { createServer } from "http";
import { Server } from "socket.io";
import cors from "cors";
import dotenv from "dotenv";
import jwt from "jsonwebtoken";
import { handleLobbyConnection, SocketUserPayload } from "./lobby.js";

dotenv.config();

const app = express();
app.use(cors({ origin: process.env.ALLOWED_ORIGIN || "http://localhost:3000" }));

const server = createServer(app);
const io = new Server(server, {
  cors: {
    origin: process.env.ALLOWED_ORIGIN || "http://localhost:3000",
    methods: ["GET", "POST"],
  },
});

const JWT_SECRET = process.env.ROOM_JWT_SECRET || "fallback-secret-for-development-only-replace-in-env";

// Middleware to authenticate socket connections
io.use((socket, next) => {
  const token = socket.handshake.auth?.token || socket.handshake.query?.token;

  if (!token) {
    return next(new Error("Authentication error: Token is required"));
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as SocketUserPayload;
    if (!decoded.roomId || !decoded.participantId || !decoded.role) {
      return next(new Error("Authentication error: Invalid token claims"));
    }

    // Attach user payload to socket
    (socket as any).user = decoded;
    next();
  } catch (err) {
    console.error("Socket authentication error:", err);
    return next(new Error("Authentication error: Invalid or expired token"));
  }
});

io.on("connection", (socket) => {
  const user = (socket as any).user as SocketUserPayload;
  console.log(`User connected: ${user.participantId} in room ${user.roomId} (Role: ${user.role})`);

  // Handle lobby joining and presence
  handleLobbyConnection(socket, user);
});

const PORT = process.env.PORT || 4000;
server.listen(PORT, () => {
  console.log(`Realtime Socket.io server running on port ${PORT}`);
});

